import{bV as d,aL as i,u as o,G as c}from"./chunks/framework.BfzMay2U.js";const u=JSON.parse('{"title":"Redis 的配置","description":"","frontmatter":{"title":"Redis 的配置","date":"2023-02-19T22:52:10.000Z","categories":["Deploy"],"tags":["redis"]},"headers":[],"relativePath":"views/deploy/redis-conf-some.md","filePath":"views/deploy/redis-conf-some.md"}'),l={name:"views/deploy/redis-conf-some.md"};function a(s,e,r,t,n,m){return i(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="redis-的配置" tabindex="-1">Redis 的配置 <a class="header-anchor" href="#redis-的配置" aria-label="Permalink to &quot;Redis 的配置&quot;">​</a></h1><h2 id="配置文件" tabindex="-1">配置文件 <a class="header-anchor" href="#配置文件" aria-label="Permalink to &quot;配置文件&quot;">​</a></h2><p><code>Redis</code>支持很多的参数，但都有默认值</p><ul><li><code>daemonize</code>默认情况下，<code>redis</code>不是在后台运行的，如果需要在后台运行，把该项的值改为<code>yes</code></li><li><code>bind</code>指定<code>Redis</code>只接受来自于该 IP 地址的请求，学习阶段就默认设置为<code>0.0.0.0</code>，放到正式服务器上的时候就需要更改。</li><li><code>port</code>监听端口，默认为 6379</li><li><code>databases</code>设置数据库的个数，有 16 个，默认使用的数据库是 0</li><li><code>save</code>设置<code>Redis</code>进行数据库镜像的频率，即是否进行数据持久化</li><li><code>dbfilename</code>镜像备份文件的文件名</li><li><code>dir</code>数据库镜像备份的文件存放的路径，持久化存储的位置</li><li><code>requirepass</code>设置客户端连接后进行热虐其他指定前需要使用的密码</li><li><code>maxclients</code>限制同时连接的客户端数</li><li><code>maxmemory</code>设置<code>redis</code>能够使用的最大内存</li></ul><h2 id="客户端访问" tabindex="-1">客户端访问 <a class="header-anchor" href="#客户端访问" aria-label="Permalink to &quot;客户端访问&quot;">​</a></h2><p>可以使用几个客户端工具</p><ul><li>redis-desktop-manager</li><li>Another-redis-desktop-manager</li><li>quickredis</li><li>等工具</li></ul><hr><ul><li>安装完后去建立连接，会提示失败，原因是<code>redis</code>默认只能本地访问</li><li>修改配置文件<code>redis.conf</code></li><li>注释掉<code>bind 127.0.0.1</code>可以使所有<code>ip</code>访问<code>redis</code>；也可以自己设置多个<code>ip</code>可以进行访问</li><li>修改后<code>kill -9 xxx</code>杀死<code>redis</code>进程，重启<code>redis</code>：重启命令：<code>systemctl restart redis.service</code></li><li>再次连接就会成功</li></ul>',9)])])}const _=d(l,[["render",a]]);export{u as __pageData,_ as default};
